query:
{
  storageAccounts(
    where: {
      OR: [
        { isTableServicesDiagnosticsSettingsEnabled: { eq: false } }
        {
          AND: [
            {
              diagnosticSettings_NONE: {
                resourceType: { eq: "Microsoft.Storage/storageAccounts/tableServices" }
                AND: [
                  { logs_SINGLE: { enabled: { eq: true }, category: { eq: "StorageRead" } } }
                  { logs_SINGLE: { enabled: { eq: true }, category: { eq: "StorageWrite" } } }
                  { logs_SINGLE: { enabled: { eq: true }, category: { eq: "StorageDelete" } } }
                ]
              }
            }
            {
              diagnosticSettings_NONE: {
                resourceType: { eq: "Microsoft.Storage/storageAccounts/tableServices" }
                logs_SOME: {
                  enabled: { eq: true }
                  categoryGroup_IN: ["audit", "allLogs"]
                }
              }
            }
          ]
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
